namespace sv_4f10ab16614043ebaf14ec857ba9d1fc.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

namespace sv_4f10ab16614043ebaf14ec857ba9d1fc.Services;

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> SeedData = new()
    {
        [1] = new List<Recipe>
        {
            new(1, "Spaghetti Carbonara", "Classic Roman pasta with eggs, pecorino, guanciale, and black pepper.", 25),
            new(2, "Margherita Pizza", "Traditional Neapolitan pizza with tomato, mozzarella, and fresh basil.", 40),
            new(3, "Risotto alla Milanese", "Creamy saffron-infused risotto from Milan.", 35),
            new(4, "Tiramisu", "Layered coffee-soaked ladyfingers with mascarpone cream.", 30),
        },
        [2] = new List<Recipe>
        {
            new(5, "Pad Thai", "Stir-fried rice noodles with shrimp, tofu, peanuts, and tamarind sauce.", 20),
            new(6, "Green Curry", "Aromatic coconut milk curry with Thai basil and vegetables.", 30),
            new(7, "Tom Yum Soup", "Hot and sour soup with lemongrass, galangal, and prawns.", 25),
            new(8, "Mango Sticky Rice", "Sweet glutinous rice topped with ripe mango and coconut cream.", 45),
        },
        [3] = new List<Recipe>
        {
            new(9, "Tacos al Pastor", "Marinated pork tacos with pineapple, cilantro, and onion.", 50),
            new(10, "Guacamole", "Fresh avocado dip with lime, cilantro, jalapeño, and tomato.", 10),
            new(11, "Enchiladas Verdes", "Corn tortillas filled with chicken and smothered in green salsa.", 40),
            new(12, "Churros", "Fried dough pastries coated in cinnamon sugar with chocolate sauce.", 35),
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call
        await Task.Delay(2000, cancellationToken);

        if (SeedData.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

@page "/recipes/{CuisineId:int}"
@rendermode InteractiveServer
@using sv_4f10ab16614043ebaf14ec857ba9d1fc.Services
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger
@inject NavigationManager Navigation
@implements IDisposable

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_error</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_recipes is null)
{
    <p><em>Loading recipes…</em></p>
}
else
{
    @if (_isRefreshing)
    {
        <p><em>Refreshing…</em></p>
    }

    <table class="table">
        <thead>
            <tr>
                <th>Title</th>
                <th>Description</th>
                <th>Prep Time (min)</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var recipe in DisplayedRecipes)
            {
                <tr>
                    <td>@recipe.Title</td>
                    <td>@recipe.Description</td>
                    <td>@recipe.PrepTimeMinutes</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public int CuisineId { get; set; }

    [SupplyParameterFromQuery(Name = "sort")]
    public string? Sort { get; set; }

    private List<Recipe>? _recipes;
    private string? _error;
    private bool _isRefreshing;
    private int _loadedCuisineId;

    private CancellationTokenSource? _cts;

    private IEnumerable<Recipe> DisplayedRecipes
    {
        get
        {
            if (_recipes is null) return Enumerable.Empty<Recipe>();

            return Sort?.ToLowerInvariant() switch
            {
                "newest" => _recipes.OrderByDescending(r => r.Id),
                "popular" => _recipes.OrderBy(r => r.PrepTimeMinutes),
                _ => _recipes,
            };
        }
    }

    protected override async Task OnParametersSetAsync()
    {
        // Only reload data if cuisine changed
        if (CuisineId == _loadedCuisineId && _recipes is not null)
        {
            return;
        }

        await LoadRecipesAsync();
    }

    private async Task LoadRecipesAsync()
    {
        // Cancel any in-flight request
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }

        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _isRefreshing = _recipes is not null;

        try
        {
            var results = await RecipeService.GetByCuisineAsync(CuisineId, token);

            if (token.IsCancellationRequested) return;

            _recipes = results;
            _loadedCuisineId = CuisineId;
        }
        catch (OperationCanceledException)
        {
            // Request was cancelled (navigation away or new cuisine selected) — do nothing
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
            _error = "Something went wrong while loading recipes. Please try again.";
        }
        finally
        {
            _isRefreshing = false;
        }
    }

    private async Task RetryAsync()
    {
        await LoadRecipesAsync();
    }

    public void Dispose()
    {
        if (_cts is not null)
        {
            _cts.Cancel();
            _cts.Dispose();
            _cts = null;
        }
    }
}

